import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.println("Enter a string:");

        // Read user input as a line to allow spaces
        String userInput = scanner.nextLine();

        // Limit the size of userInput to avoid buffer overflow
        int maxLength = 10;
        if (userInput.length() > maxLength) {
            System.out.println("Input exceeds maximum allowed length.");
            return;
        }

        // Create a char array with size equal to userInput length
        char[] buffer = new char[userInput.length()];

        // Copy user input into the buffer array
        userInput.getChars(0, userInput.length(), buffer, 0);

        // Print the content of the buffer array
        System.out.println("Buffer content: " + new String(buffer));
    }
}

